PROCEDURE hasNegative(numList)
{
    FOR EACH n IN numList
    {
        IF(n < 0)
        {
            RETURN(true)
        }
    }
    RETURN(false)
}

DISPLAY(hasNegative([5, -3, 8, 2]))
DISPLAY(hasNegative([1, 2, 3]))

nums ← [3, 7, 1, 9, 4, 6, 2, 8, 5]
target ← 6
found ← false
FOR EACH n IN nums
{
    IF(n = target)
    {
        found ← true
    }
}
DISPLAY(found)

PROCEDURE mystery(list)
{
    maxVal ← list[1]
    FOR EACH item IN list
    {
        IF(item > maxVal)
        {
            maxVal ← item
        }
    }
    RETURN(maxVal)
}

DISPLAY(mystery([4, 7, 2, 9, 1, 5]))

n ← 7
IF(n MOD 2 = 0)
{
    DISPLAY("even")
}
ELSE
{
    DISPLAY("odd")
}

PROCEDURE filterPositive(numList)
{
    result ← []
    FOR EACH n IN numList
    {
        IF(n > 0)
        {
            APPEND(result, n)
        }
    }
    RETURN(result)
}

DISPLAY(filterPositive([-3, 5, -1, 8, 0, 2]))

x ← 1
REPEAT 4 TIMES
{
    x ← x + x
}
DISPLAY(x)

PROCEDURE isEven(n)
{
    IF(n MOD 2 = 0)
    {
        RETURN(true)
    }
    ELSE
    {
        RETURN(false)
    }
}

evens ← []
FOR EACH num IN [1, 2, 3, 4, 5, 6]
{
    IF(isEven(num))
    {
        APPEND(evens, num)
    }
}
DISPLAY(evens)

PROCEDURE countdown(n)
{
    IF(n <= 0)
    {
        DISPLAY("Go!")
    }
    ELSE
    {
        DISPLAY(n)
        countdown(n - 1)
    }
}

